import { readFile, writeFile, mkdir } from "node:fs/promises";
import { join, dirname, relative } from "node:path";

export interface SourceEdit {
  file: string;
  search: string;
  replace: string;
  reason: string;
}

export interface EditResult {
  success: boolean;
  file: string;
  message: string;
  diff?: {
    linesRemoved: number;
    linesAdded: number;
    charDelta: number;
  };
}

export interface EditBatchResult {
  results: EditResult[];
  rollbackSnapshots: Map<string, string>;
}

/**
 * Apply a single search/replace edit to a source file.
 * The search block must match exactly (including whitespace).
 */
export async function applySourceEdit(
  cwd: string,
  edit: SourceEdit,
  backupDir?: string
): Promise<EditResult> {
  const filePath = join(cwd, edit.file);

  let original: string;
  try {
    original = await readFile(filePath, "utf8");
  } catch (error) {
    return {
      success: false,
      file: edit.file,
      message: `Cannot read file: ${error instanceof Error ? error.message : String(error)}`,
    };
  }

  const searchNormalized = edit.search.replace(/\r\n/g, "\n");
  const contentNormalized = original.replace(/\r\n/g, "\n");

  if (!contentNormalized.includes(searchNormalized)) {
    return {
      success: false,
      file: edit.file,
      message:
        `Search block not found in file. Ensure the search text matches exactly, including ` +
        `indentation and newlines. File: ${edit.file}`,
    };
  }

  // Count occurrences
  const occurrences = contentNormalized.split(searchNormalized).length - 1;
  if (occurrences > 1) {
    return {
      success: false,
      file: edit.file,
      message:
        `Search block appears ${occurrences} times in the file. ` +
        `Edit rejected for safety — include more surrounding context to make the search unique.`,
    };
  }

  const nextContent = contentNormalized.replace(searchNormalized, edit.replace);

  // Create backup if requested
  if (backupDir) {
    const backupPath = join(backupDir, edit.file.replace(/[/\\]/g, "__"));
    await mkdir(dirname(backupPath), { recursive: true });
    await writeFile(backupPath, original, "utf8");
  }

  await writeFile(filePath, nextContent, "utf8");

  const linesRemoved = searchNormalized.split("\n").length;
  const linesAdded = edit.replace.split("\n").length;

  return {
    success: true,
    file: edit.file,
    message: `Edited ${edit.file}: ${linesRemoved} lines removed, ${linesAdded} lines added. Reason: ${edit.reason}`,
    diff: {
      linesRemoved,
      linesAdded,
      charDelta: edit.replace.length - searchNormalized.length,
    },
  };
}

/**
 * Apply multiple edits in sequence.
 * If any edit fails, returns immediately with rollback info for the edits that succeeded.
 */
export async function applySourceEdits(
  cwd: string,
  edits: SourceEdit[],
  backupDir?: string
): Promise<EditBatchResult> {
  const results: EditResult[] = [];
  const rollbackSnapshots = new Map<string, string>();

  for (const edit of edits) {
    // Read current content for snapshot (in case prior edit touched the same file)
    const filePath = join(cwd, edit.file);
    let currentContent: string;
    try {
      currentContent = await readFile(filePath, "utf8");
    } catch {
      // File doesn't exist — snapshot is empty
      currentContent = "";
    }

    // Store snapshot keyed by file path for rollback
    if (!rollbackSnapshots.has(edit.file)) {
      rollbackSnapshots.set(edit.file, currentContent);
    }

    const result = await applySourceEdit(cwd, edit, backupDir);
    results.push(result);

    if (!result.success) {
      break;
    }
  }

  return { results, rollbackSnapshots };
}

/**
 * Rollback files to their pre-edit state.
 */
export async function rollbackEdits(
  cwd: string,
  snapshots: Map<string, string>
): Promise<void> {
  for (const [file, content] of snapshots) {
    const filePath = join(cwd, file);
    await writeFile(filePath, content, "utf8");
  }
}

/**
 * Format an edit result as human-readable markdown.
 */
export function editResultToMarkdown(results: EditResult[]): string {
  const lines = ["# Source Edit Report", ""];

  const succeeded = results.filter((r) => r.success);
  const failed = results.filter((r) => !r.success);

  lines.push(`- Succeeded: ${succeeded.length}`);
  lines.push(`- Failed: ${failed.length}`);
  lines.push("");

  if (succeeded.length > 0) {
    lines.push("## Applied Changes");
    lines.push("");
    for (const r of succeeded) {
      lines.push(`- **${r.file}** — ${r.message}`);
      if (r.diff) {
        lines.push(
          `  - Δ ${r.diff.charDelta >= 0 ? "+" : ""}${r.diff.charDelta} chars, ` +
            `${r.diff.linesRemoved}→${r.diff.linesAdded} lines`
        );
      }
    }
    lines.push("");
  }

  if (failed.length > 0) {
    lines.push("## Failures");
    lines.push("");
    for (const r of failed) {
      lines.push(`- **${r.file}** — ${r.message}`);
    }
    lines.push("");
  }

  return lines.join("\n");
}

import { describe, test, expect, beforeEach, afterEach } from "bun:test";
import { mkdtemp, writeFile, readFile } from "node:fs/promises";
import { join } from "node:path";
import { tmpdir } from "node:os";
import { rmSync } from "node:fs";
import { applySourceEdit, applySourceEdits, rollbackEdits, editResultToMarkdown } from "../src/core/code-edit.js";

async function makeTmpDir(): Promise<string> {
  return mkdtemp(join(tmpdir(), "keating-code-edit-"));
}

describe("applySourceEdit", () => {
  let cwd: string;

  beforeEach(async () => { cwd = await makeTmpDir(); });
  afterEach(() => { try { rmSync(cwd, { recursive: true }); } catch {} });

  test("applies a simple search/replace", async () => {
    await writeFile(join(cwd, "test.ts"), "const a = 1;\nconst b = 2;\n", "utf8");
    const result = await applySourceEdit(cwd, {
      file: "test.ts",
      search: "const a = 1;",
      replace: "const a = 42;",
      reason: "update value",
    });
    expect(result.success).toBe(true);
    expect(result.diff?.linesRemoved).toBe(1);
    expect(result.diff?.linesAdded).toBe(1);
    expect(await readFile(join(cwd, "test.ts"), "utf8")).toBe("const a = 42;\nconst b = 2;\n");
  });

  test("rejects when search block not found", async () => {
    await writeFile(join(cwd, "test.ts"), "const a = 1;\n", "utf8");
    const result = await applySourceEdit(cwd, {
      file: "test.ts",
      search: "const z = 99;",
      replace: "const z = 0;",
      reason: "missing",
    });
    expect(result.success).toBe(false);
    expect(result.message).toContain("Search block not found");
  });

  test("rejects when search block is ambiguous", async () => {
    await writeFile(join(cwd, "test.ts"), "const x = 1;\nconst x = 1;\n", "utf8");
    const result = await applySourceEdit(cwd, {
      file: "test.ts",
      search: "const x = 1;",
      replace: "const x = 2;",
      reason: "ambiguous",
    });
    expect(result.success).toBe(false);
    expect(result.message).toContain("appears 2 times");
  });

  test("rejects when file does not exist", async () => {
    const result = await applySourceEdit(cwd, {
      file: "missing.ts",
      search: "a",
      replace: "b",
      reason: "missing file",
    });
    expect(result.success).toBe(false);
    expect(result.message).toContain("Cannot read file");
  });

  test("creates backup when backupDir is provided", async () => {
    await writeFile(join(cwd, "test.ts"), "original\n", "utf8");
    const backupDir = join(cwd, ".backups");
    const result = await applySourceEdit(cwd, {
      file: "test.ts",
      search: "original",
      replace: "modified",
      reason: "test backup",
    }, backupDir);
    expect(result.success).toBe(true);
    const backupContent = await readFile(join(backupDir, "test.ts"), "utf8");
    expect(backupContent).toBe("original\n");
  });
});

describe("applySourceEdits batch", () => {
  let cwd: string;

  beforeEach(async () => { cwd = await makeTmpDir(); });
  afterEach(() => { try { rmSync(cwd, { recursive: true }); } catch {} });

  test("applies multiple edits in sequence", async () => {
    await writeFile(join(cwd, "test.ts"), "const a = 1;\nconst b = 2;\nconst c = 3;\n", "utf8");
    const { results } = await applySourceEdits(cwd, [
      { file: "test.ts", search: "const a = 1;", replace: "const a = 10;", reason: "a" },
      { file: "test.ts", search: "const b = 2;", replace: "const b = 20;", reason: "b" },
    ]);
    expect(results[0].success).toBe(true);
    expect(results[1].success).toBe(true);
    const content = await readFile(join(cwd, "test.ts"), "utf8");
    expect(content).toBe("const a = 10;\nconst b = 20;\nconst c = 3;\n");
  });

  test("stops on first failure and provides rollback snapshots", async () => {
    await writeFile(join(cwd, "test.ts"), "const a = 1;\nconst b = 2;\n", "utf8");
    const { results, rollbackSnapshots } = await applySourceEdits(cwd, [
      { file: "test.ts", search: "const a = 1;", replace: "const a = 10;", reason: "a" },
      { file: "test.ts", search: "NOT_FOUND", replace: "x", reason: "fail" },
    ]);
    expect(results[0].success).toBe(true);
    expect(results[1].success).toBe(false);
    expect(rollbackSnapshots.has("test.ts")).toBe(true);
    expect(rollbackSnapshots.get("test.ts")).toBe("const a = 1;\nconst b = 2;\n");
  });
});

describe("rollbackEdits", () => {
  let cwd: string;

  beforeEach(async () => { cwd = await makeTmpDir(); });
  afterEach(() => { try { rmSync(cwd, { recursive: true }); } catch {} });

  test("restores files from snapshots", async () => {
    await writeFile(join(cwd, "test.ts"), "const a = 1;\n", "utf8");
    await applySourceEdit(cwd, { file: "test.ts", search: "const a = 1;", replace: "const a = 99;", reason: "change" });

    const snapshots = new Map<string, string>();
    snapshots.set("test.ts", "const a = 1;\n");
    await rollbackEdits(cwd, snapshots);

    expect(await readFile(join(cwd, "test.ts"), "utf8")).toBe("const a = 1;\n");
  });
});

describe("editResultToMarkdown", () => {
  test("formats success and failure", () => {
    const md = editResultToMarkdown([
      { success: true, file: "a.ts", message: "ok", diff: { linesRemoved: 2, linesAdded: 3, charDelta: 5 } },
      { success: false, file: "b.ts", message: "not found" },
    ]);
    expect(md).toContain("Succeeded: 1");
    expect(md).toContain("Failed: 1");
    expect(md).toContain("a.ts");
    expect(md).toContain("b.ts");
    expect(md).toContain("not found");
  });
});

